import{_ as a,o as t,c as n,a2 as r}from"./chunks/framework.CHeM0PsO.js";const u=JSON.parse('{"title":"Start using Sovereign","description":"Find a Sovereign instance and understand the operator relationship before joining.","frontmatter":{"title":"Start using Sovereign","description":"Find a Sovereign instance and understand the operator relationship before joining."},"headers":[],"relativePath":"get-started/users.md","filePath":"get-started/users.md"}'),o={name:"get-started/users.md"};function i(s,e,c,p,h,l){return t(),n("div",null,[...e[0]||(e[0]=[r('<h1 id="start-using-sovereign" tabindex="-1">Start using Sovereign <a class="header-anchor" href="#start-using-sovereign" aria-label="Permalink to &quot;Start using Sovereign&quot;">​</a></h1><p>You use Sovereign through an instance run by an operator. The Sovereign project does not create a global account that automatically grants access to every instance.</p><h2 id="_1-find-an-instance" tabindex="-1">1. Find an instance <a class="header-anchor" href="#_1-find-an-instance" aria-label="Permalink to &quot;1. Find an instance&quot;">​</a></h2><p>Open the <a href="/instances.html">instance directory</a>. Review the intended audience, access policy, operator, installed apps, and last verification date.</p><h2 id="_2-review-the-operator" tabindex="-1">2. Review the operator <a class="header-anchor" href="#_2-review-the-operator" aria-label="Permalink to &quot;2. Review the operator&quot;">​</a></h2><p>The operator controls accounts, policies, infrastructure, apps, backups, retention, and support. Read the operator&#39;s privacy and service terms before creating an account or adding data.</p><h2 id="_3-obtain-access" tabindex="-1">3. Obtain access <a class="header-anchor" href="#_3-obtain-access" aria-label="Permalink to &quot;3. Obtain access&quot;">​</a></h2><p>Registration may be open, approval-based, invite-only, or limited to a demonstration. Follow the policy shown for that instance. Do not assume a visible registration form guarantees access or a particular service commitment.</p><h2 id="_4-enter-the-workspace" tabindex="-1">4. Enter the workspace <a class="header-anchor" href="#_4-enter-the-workspace" aria-label="Permalink to &quot;4. Enter the workspace&quot;">​</a></h2><p>After signing in, the Launcher shows the apps available to you. Account settings cover your profile and security options. Other apps and permissions depend on the operator&#39;s configuration.</p><h2 id="_5-install-it-as-an-app" tabindex="-1">5. Install it as an app <a class="header-anchor" href="#_5-install-it-as-an-app" aria-label="Permalink to &quot;5. Install it as an app&quot;">​</a></h2><p>Install the instance as a PWA to give it a Home Screen, app launcher, or desktop icon and open it in a standalone window. An installed app can also receive push notifications when the operator and device support them.</p><p><a href="/docs/pwa.html">Follow the PWA installation and notification steps</a></p><h2 id="_6-ask-the-operator-for-support" tabindex="-1">6. Ask the operator for support <a class="header-anchor" href="#_6-ask-the-operator-for-support" aria-label="Permalink to &quot;6. Ask the operator for support&quot;">​</a></h2><p>Account access and instance data are controlled by the operator. Use the support channel listed for that instance rather than contacting an unrelated operator or the Sovereign project.</p>',15)])])}const g=a(o,[["render",i]]);export{u as __pageData,g as default};
